int main() {
    // Example 1: Comparing Integers
    int num1 = 5;  // num1 holds an integer value of 5
    int num2 = 10;  // num2 holds an integer value of 10
    printf("Example 1: %d\n", num1 <= num2);  // Outputs: 1 (true)

    // Example 2: Comparing Floating-Point Numbers
    double price1 = 8.99; // price1 holds a double value of 8.99
    double price2 = 9.99; // price2 holds a double value of 9.99
    printf("Example 2: %d\n", price1 <= price2);  // Outputs: 1 (true)

    // Example 3: Comparing Mixed Types (Int and Float)
    int x = 7;    // x holds the integer value 7
    float y = 10.0f; // y holds the float value 10.0
    printf("Example 3: %d\n", x <= y);  // Outputs: 1 (true)

    return 0;
}
